#!/usr/bin/env python3
import base64, os, subprocess

b64_collect = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/collect.js"), exist_ok=True)
open("/var/www/konverta/src/routes/collect.js", "wb").write(base64.b64decode(b64_collect))
print("✓ /var/www/konverta/src/routes/collect.js")

b64_script = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/script.js"), exist_ok=True)
open("/var/www/konverta/src/routes/script.js", "wb").write(base64.b64decode(b64_script))
print("✓ /var/www/konverta/src/routes/script.js")

b64_geo_cache = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/geo-cache.js"), exist_ok=True)
open("/var/www/konverta/src/geo-cache.js", "wb").write(base64.b64decode(b64_geo_cache))
print("✓ /var/www/konverta/src/geo-cache.js")

print("\n✅ Pronto!")
subprocess.run(["pm2", "restart", "konverta"])